arguments.new_str:
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Train the model at startup so the file exists for the prediction pool
using var trainLoggerFactory = LoggerFactory.Create(b => b.AddConsole());
var modelPath = ModelTrainingService.TrainAndSaveModel(trainLoggerFactory);

builder.Services.AddPredictionEnginePool<TicketData, TicketPrediction>()
    .FromFile(modelPath);

var app = builder.Build();
app.MapControllers();
app.Run();

